// Mapează platforma din frontend la marketplace-ul canonic din catalogs
const body = $input.first().json.body || {};
const platform = (body.platform || 'emag').toLowerCase();
const platformMap = {
  'emag': 'emag_ro',
  'trendyol': 'trendyol_ro',
  'temu': 'temu_ro'
};
const marketplace = platformMap[platform] || (platform + '_ro');
const categoryId = String(body.categoryId || '');

if (!categoryId) {
  return [{ json: { _error: true, attributes: [] } }];
}

return [{ json: { marketplace, categoryId } }];

// Formatează rezultatele Postgres în structura așteptată de frontend
const rows = $input.all().map(item => item.json);

// Dacă nu sunt rezultate sau e eroare de la Prepare
if (rows.length === 1 && !rows[0].characteristic_id) {
  return [{ json: { attributes: [] } }];
}

const attributes = rows.map(row => {
  // Parsează attr_values dacă e string JSON
  let values = row.attr_values || [];
  if (typeof values === 'string') {
    try { values = JSON.parse(values); } catch(e) { values = []; }
  }

  return {
    id: String(row.characteristic_id),
    name: row.characteristic_name,
    nameRo: row.name_ro || null,
    // type_id: 1=text, 2=select, 3=number, 4=multiselect
    type: [2, 4].includes(row.type_id) ? 'select' : 'text',
    required: row.is_mandatory === true,
    allowsCustom: row.allows_custom === true,
    values: values.filter(v => v.id !== null)
  };
});

return [{ json: { attributes } }];
